/** @internal @packageDocumentation */
import type { AxiosInstance } from 'axios'
import m3u8stream from 'm3u8stream'
import { handleRequestErrs, appendURL } from './util'

// Konfigurowalny timeout z sensownym defaultem
const DEFAULT_API_TIMEOUT = 20000; // 20 sekund
const DEFAULT_STREAM_TIMEOUT = 30000; // 30 sekund
const MAX_RETRIES = 3;

/**
 * Maskuje wrażliwe parametry w URL (np. client_id, oauth_token)
 */
const sanitizeURL = (url: string): string => {
  return url
    .replace(/(client_id=)[^&]+/gi, '$1***')
    .replace(/(oauth_token=)[^&]+/gi, '$1***')
    .replace(/(auth_token=)[^&]+/gi, '$1***');
}

const fromURL = async (
  url: string,
  clientID: string,
  axiosInstance: AxiosInstance,
  options?: {
    apiTimeout?: number;
    streamTimeout?: number;
  }
): Promise<any | m3u8stream.Stream> => {
  // Walidacja wejścia
  if (!url || typeof url !== 'string') {
    throw new Error('Invalid URL parameter');
  }
  if (!clientID || typeof clientID !== 'string') {
    throw new Error('Invalid clientID parameter');
  }
  if (!axiosInstance) {
    throw new Error('Axios instance is required');
  }

  const apiTimeout = options?.apiTimeout || DEFAULT_API_TIMEOUT;
  const streamTimeout = options?.streamTimeout || DEFAULT_STREAM_TIMEOUT;
  // Walidacja timeoutów
  if (!Number.isFinite(apiTimeout) || apiTimeout <= 0) {
    throw new Error('apiTimeout must be a positive number');
  }
  if (!Number.isFinite(streamTimeout) || streamTimeout <= 0) {
    throw new Error('streamTimeout must be a positive number');
  }
  try {
    const link = appendURL(url, 'client_id', clientID);

    const res = await axiosInstance.get(link, {
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/150.0.0.0 Safari/537.36',
        'Accept': '*/*',
        'Accept-Encoding': 'gzip, deflate, br',
        'Referer': 'https://soundcloud.com/'
      },
      withCredentials: true,
      timeout: apiTimeout
    });

    // Walidacja odpowiedzi
    if (!res.data) {
      throw new Error('Empty response from SoundCloud API');
    }

    if (!res.data.url) {
      const safeLink = sanitizeURL(link);
      throw new Error(
        `Invalid response from SoundCloud. Missing 'url' field. Check if the URL is correct: ${safeLink}`
      );
    }

    // Użyj faktycznego URL ze odpowiedzi, nie wejściowego URL
    const streamURL: string = res.data.url;

    // Progressive download z retry logic
    // Sprawdzamy streamURL (nie wejściowy url) aby prawidłowo wykryć typ
    if (streamURL.includes('/progressive')) {
      let lastError: unknown;

      for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
        try {
          const streamRes = await axiosInstance.get(streamURL, {
            withCredentials: true,
            responseType: 'stream',
            timeout: streamTimeout,
            headers: {
              'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/150.0.0.0 Safari/537.36',
              'Accept': '*/*',
              'Referer': 'https://soundcloud.com/'
            }
          });

          if (!streamRes.data) {
            throw new Error('Failed to retrieve audio stream');
          }

          return streamRes.data;
        } catch (streamErr) {
          lastError = streamErr;

          // Jeśli to nie ostatnia próba, czekaj przed ponowieniem
          if (attempt < MAX_RETRIES - 1) {
            await new Promise(resolve =>
              setTimeout(resolve, 1000 * (attempt + 1))
            );
            continue;
          }
        }
      }

      throw new Error(
        `Failed to download progressive stream after ${MAX_RETRIES} attempts`,
        { cause: lastError }
      );
    }

    // HLS stream z retry logic
    try {
      return m3u8stream(streamURL, {
        requestOptions: {
          maxRetries: MAX_RETRIES,
          maxReconnects: MAX_RETRIES,
          headers: {
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/150.0.0.0 Safari/537.36',
            'Referer': 'https://soundcloud.com/'
          }
        }
      });
    } catch (m3u8Err) {
      throw new Error('Failed to create HLS stream', { cause: m3u8Err });
    }

  } catch (err) {
    throw handleRequestErrs(err);
  }
}

export default fromURL;
